const DEV_LOG_BATCH_CHANNEL = "dev-log:append-batch";
const DEV_LOG_META_KEY = "__nexusDevLogMeta";
const DEV_LOG_INTERNAL_MARKER = "__NEXUS_DEV_LOG_INTERNAL__";

const { ipcRenderer } = window.require("electron");

const devLogRawConsole = {
  debug: console.debug.bind(console),
  log: console.log.bind(console),
  info: console.info.bind(console),
  warn: console.warn.bind(console),
  error: console.error.bind(console),
};

const rendererDevLogState = {
  queue: Array.isArray(window.__NEXUS_DEV_LOG_BUFFER__)
    ? window.__NEXUS_DEV_LOG_BUFFER__
    : [],
  flushTimer: null,
  consoleBridgeInstalled: false,
  ipcBridgeInstalled: false,
  initialized: false,
  verbose: window.localStorage?.getItem("NEXUS_DEV_LOG_VERBOSE") === "1",
};

window.__NEXUS_DEV_LOG_BUFFER__ = rendererDevLogState.queue;
window.__NEXUS_DEV_LOG_RUN_ID__ =
  window.__NEXUS_DEV_LOG_RUN_ID__
  || (globalThis.crypto?.randomUUID?.()
    || `renderer-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`);

function getRendererRunId() {
  return window.__NEXUS_DEV_LOG_RUN_ID__;
}

function shouldMirrorRendererConsole(level) {
  return level === "warn" || level === "error" || level === "fatal";
}

function resolveRendererScope(scope) {
  const normalizedScope = String(scope || "").trim() || "renderer.startup";

  if (normalizedScope.startsWith("renderer.startup")) {
    return {
      process: "renderer",
      surface: "startup",
      subsystem: normalizedScope,
      shard: "40-renderer-startup.jsonl",
    };
  }

  if (normalizedScope.startsWith("renderer.store") || normalizedScope.startsWith("renderer.items")) {
    return {
      process: "renderer",
      surface: "store",
      subsystem: normalizedScope,
      shard: "41-renderer-store.jsonl",
    };
  }

  if (normalizedScope.startsWith("renderer.explorer")) {
    return {
      process: "renderer",
      surface: "explorer",
      subsystem: normalizedScope,
      shard: "42-renderer-explorer.jsonl",
    };
  }

  if (normalizedScope.startsWith("renderer.editors")) {
    return {
      process: "renderer",
      surface: "editors",
      subsystem: normalizedScope,
      shard: "43-renderer-editors.jsonl",
    };
  }

  if (normalizedScope.startsWith("renderer.plugins")) {
    return {
      process: "renderer",
      surface: "plugins",
      subsystem: normalizedScope,
      shard: "44-renderer-plugins.jsonl",
    };
  }

  if (normalizedScope.startsWith("renderer.ipc")) {
    return {
      process: "renderer",
      surface: "ipc",
      subsystem: normalizedScope,
      shard: "50-ipc.jsonl",
    };
  }

  return {
    process: "renderer",
    surface: "startup",
    subsystem: normalizedScope,
    shard: "40-renderer-startup.jsonl",
  };
}

function serializeUnknown(value, seen = new WeakSet()) {
  if (value instanceof Error) {
    return {
      name: value.name,
      message: value.message,
      stack: value.stack || null,
      cause: serializeUnknown(value.cause, seen),
    };
  }

  if (typeof value === "bigint") {
    return value.toString();
  }

  if (Array.isArray(value)) {
    return value.map((entry) => serializeUnknown(entry, seen));
  }

  if (value && typeof value === "object") {
    if (seen.has(value)) {
      return "[circular]";
    }

    seen.add(value);
    const serialized = Object.fromEntries(
      Object.entries(value).map(([key, entry]) => [key, serializeUnknown(entry, seen)]),
    );
    seen.delete(value);
    return serialized;
  }

  return value ?? null;
}

function summarizeValue(value, depth = 0) {
  if (depth >= 2) {
    return "[max-depth]";
  }

  if (typeof value === "string") {
    return value.length > 240 ? `${value.slice(0, 240)}...` : value;
  }

  if (Array.isArray(value)) {
    return {
      type: "array",
      length: value.length,
      sample: value.slice(0, 4).map((entry) => summarizeValue(entry, depth + 1)),
    };
  }

  if (value && typeof value === "object") {
    const objectValue = value;
    const keys = Object.keys(objectValue);
    const summary = {
      type: "object",
      keys: keys.slice(0, 12),
      keyCount: keys.length,
    };

    for (const key of [
      "id",
      "itemId",
      "parentId",
      "filePath",
      "pluginId",
      "enabled",
      "version",
      "offset",
      "limit",
      "directoryName",
      "developmentMode",
      "reason",
    ]) {
      if (key in objectValue) {
        summary[key] = summarizeValue(objectValue[key], depth + 1);
      }
    }

    if ("paths" in objectValue && Array.isArray(objectValue.paths)) {
      summary.pathsCount = objectValue.paths.length;
    }

    return summary;
  }

  return value ?? null;
}

function buildRendererEvent(partialEvent = {}) {
  return {
    ts: partialEvent.ts || new Date().toISOString(),
    rendererRunId: partialEvent.rendererRunId || getRendererRunId(),
    process: "renderer",
    surface: partialEvent.surface || "startup",
    subsystem: partialEvent.subsystem || "renderer.startup",
    level: partialEvent.level || "info",
    event: partialEvent.event || "renderer.unspecified",
    message: partialEvent.message || "",
    durationMs:
      typeof partialEvent.durationMs === "number"
        ? Number(partialEvent.durationMs.toFixed(2))
        : null,
    requestId: partialEvent.requestId || null,
    data: partialEvent.data ? serializeUnknown(partialEvent.data) : null,
    shard: partialEvent.shard || null,
  };
}

export function queueRendererDevLogEvent(partialEvent = {}) {
  rendererDevLogState.queue.push(buildRendererEvent(partialEvent));

  if (shouldMirrorRendererConsole(partialEvent.level || "info")) {
    const rawMethod =
      partialEvent.level === "warn"
        ? devLogRawConsole.warn
        : devLogRawConsole.error;
    rawMethod(partialEvent.message || partialEvent.event || "", partialEvent.data || "");
  }

  scheduleRendererDevLogFlush();
}

function scheduleRendererDevLogFlush() {
  if (rendererDevLogState.flushTimer) {
    return;
  }

  rendererDevLogState.flushTimer = window.setTimeout(() => {
    rendererDevLogState.flushTimer = null;
    flushRendererDevLogBuffer();
  }, 80);
}

export function flushRendererDevLogBuffer() {
  if (!rendererDevLogState.queue.length) {
    return;
  }

  const events = rendererDevLogState.queue.splice(0, rendererDevLogState.queue.length);

  try {
    ipcRenderer.send(DEV_LOG_BATCH_CHANNEL, {
      events,
    });
  } catch (error) {
    rendererDevLogState.queue.unshift(...events);
    devLogRawConsole.error("[dev-log] No se pudo flush-ear el batch del renderer.", error);
  }
}

function inferSourceFromStack() {
  const error = new Error();
  const stack = typeof error.stack === "string" ? error.stack.split("\n").slice(1) : [];

  for (const rawLine of stack) {
    const line = rawLine.trim();
    if (!line || line.includes("/src/utils/devLog.js")) {
      continue;
    }

    const match = line.match(/\(?((?:https?:\/\/|file:\/\/\/)[^\s)]+):(\d+):(\d+)\)?$/);
    if (!match) {
      continue;
    }

    return {
      filePath: match[1],
      line: Number.parseInt(match[2], 10),
      column: Number.parseInt(match[3], 10),
    };
  }

  return {
    filePath: "",
    line: null,
    column: null,
  };
}

function resolveRendererScopeBySourceFile(filePath) {
  const normalized = String(filePath || "").toLowerCase();

  if (normalized.includes("/src/store/")) {
    return resolveRendererScope("renderer.store.console");
  }

  if (normalized.includes("/src/components/fileexplorer/")) {
    return resolveRendererScope("renderer.explorer.console");
  }

  if (normalized.includes("/src/editors/")) {
    return resolveRendererScope("renderer.editors.console");
  }

  if (normalized.includes("/src/plugins/")) {
    return resolveRendererScope("renderer.plugins.console");
  }

  if (normalized.includes("/src/main.jsx") || normalized.includes("/src/utils/startuptrace.js")) {
    return resolveRendererScope("renderer.startup.console");
  }

  return resolveRendererScope("renderer.startup.console");
}

function formatConsoleArgs(args) {
  return args.map((entry) => {
    if (typeof entry === "string") {
      return entry;
    }

    try {
      return JSON.stringify(serializeUnknown(entry));
    } catch {
      return String(entry);
    }
  }).join(" ");
}

export function installRendererDevConsoleBridge() {
  if (rendererDevLogState.consoleBridgeInstalled) {
    return;
  }

  const bridgeMethod = (methodName, level) => (...args) => {
    if (window[DEV_LOG_INTERNAL_MARKER]) {
      const rawMethod = devLogRawConsole[methodName] || devLogRawConsole.log;
      rawMethod(...args);
      return;
    }

    const source = inferSourceFromStack();
    const scope = resolveRendererScopeBySourceFile(source.filePath);
    const message = formatConsoleArgs(args);

    try {
      window[DEV_LOG_INTERNAL_MARKER] = true;
      queueRendererDevLogEvent({
        ...scope,
        level,
        event: `console.${methodName}`,
        message,
        data: {
          args: serializeUnknown(args),
          sourceFile: source.filePath || null,
          sourceLine: source.line,
          sourceColumn: source.column,
        },
      });
    } finally {
      delete window[DEV_LOG_INTERNAL_MARKER];
    }

    if ((level === "debug" || level === "info") && rendererDevLogState.verbose) {
      const rawMethod = devLogRawConsole[methodName] || devLogRawConsole.log;
      rawMethod(...args);
    }
  };

  console.debug = bridgeMethod("debug", "debug");
  console.log = bridgeMethod("log", "info");
  console.info = bridgeMethod("info", "info");
  console.warn = bridgeMethod("warn", "warn");
  console.error = bridgeMethod("error", "error");
  rendererDevLogState.consoleBridgeInstalled = true;
}

function shouldAlwaysLogIpcChannel(channel) {
  return [
    "create-item",
    "update-item",
    "delete-item",
    "delete-item-permanently",
    "move-item",
    "move-items",
    "import-external-items",
    "trash:restore-item",
    "trash:purge-item",
    "vault:reindex",
  ].includes(channel) ||
    (channel.startsWith("plugins:") && channel !== "plugins:list");
}

export function installRendererIpcInvokeBridge() {
  if (rendererDevLogState.ipcBridgeInstalled) {
    return;
  }

  const originalInvoke = ipcRenderer.invoke.bind(ipcRenderer);

  ipcRenderer.invoke = async (channel, ...args) => {
    const requestId =
      globalThis.crypto?.randomUUID?.()
      || `ipc-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
    const startedAt = performance.now();
    const alwaysLog = shouldAlwaysLogIpcChannel(channel);
    const payloadSummary = args.map((entry) => summarizeValue(entry));

    if (alwaysLog) {
      queueRendererDevLogEvent({
        ...resolveRendererScope("renderer.ipc"),
        level: "info",
        event: "ipc.invoke.start",
        message: `IPC ${channel} iniciado desde renderer.`,
        requestId,
        data: {
          channel,
          payloadSummary,
        },
      });
    }

    try {
      const result = await originalInvoke(channel, ...args, {
        [DEV_LOG_META_KEY]: {
          requestId,
          rendererRunId: getRendererRunId(),
          source: "renderer",
        },
      });
      const durationMs = Number((performance.now() - startedAt).toFixed(2));

      if (alwaysLog || durationMs >= 25) {
        queueRendererDevLogEvent({
          ...resolveRendererScope("renderer.ipc"),
          level: durationMs >= 100 ? "warn" : "info",
          event: "ipc.invoke.done",
          message: `IPC ${channel} completado en renderer.`,
          requestId,
          durationMs,
          data: {
            channel,
            payloadSummary,
            resultSummary: summarizeValue(result),
          },
        });
      }

      return result;
    } catch (error) {
      queueRendererDevLogEvent({
        ...resolveRendererScope("renderer.ipc"),
        level: "error",
        event: "ipc.invoke.error",
        message: `IPC ${channel} fallo en renderer.`,
        requestId,
        durationMs: Number((performance.now() - startedAt).toFixed(2)),
        data: {
          channel,
          payloadSummary,
          error: serializeUnknown(error),
        },
      });
      throw error;
    }
  };

  rendererDevLogState.ipcBridgeInstalled = true;
}

export function createRendererDevLogger(scope) {
  const context = resolveRendererScope(scope);
  return {
    context,
    debug(event, message, data = null) {
      queueRendererDevLogEvent({ ...context, level: "debug", event, message, data });
    },
    info(event, message, data = null) {
      queueRendererDevLogEvent({ ...context, level: "info", event, message, data });
    },
    warn(event, message, data = null) {
      queueRendererDevLogEvent({ ...context, level: "warn", event, message, data });
    },
    error(event, message, data = null) {
      queueRendererDevLogEvent({ ...context, level: "error", event, message, data });
    },
  };
}

export function initRendererDevLogging() {
  if (rendererDevLogState.initialized) {
    return;
  }

  window.__queueNexusDevLogEvent = (event) => {
    queueRendererDevLogEvent(event);
  };
  window.__flushNexusDevLogBuffer = () => {
    flushRendererDevLogBuffer();
  };

  installRendererDevConsoleBridge();
  installRendererIpcInvokeBridge();
  rendererDevLogState.initialized = true;

  queueRendererDevLogEvent({
    ...resolveRendererScope("renderer.startup"),
    level: "info",
    event: "renderer.devLog.initialized",
    message: "Infraestructura de dev-log del renderer inicializada.",
    data: {
      rendererRunId: getRendererRunId(),
    },
  });

  flushRendererDevLogBuffer();
}
